SELECT DISTINCT DATE_FORMAT(Time, '%Y-%m-%d %H:%i') as Time FROM `wavedata` where Channel in
#{item}
ORDER BY Time desc

SELECT * FROM `wavedata`
where Channel in

    #{item}

and DATE_FORMAT(Time, '%Y-%m-%d %H:%i') = #{time}
ORDER BY Time desc

SELECT `Index`,Time,DeviceId,Channel,Number,Distance,Wavelength FROM `wavedata`
where Channel =#{channelId}
and time < #{time}
ORDER BY Time desc
limit #{count}
